import { useState } from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

// Map condition strings to weather emojis
const getWeatherEmoji = (condition: string): string => {
  const lower = condition.toLowerCase();
  if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloud')) return '☁️';
  if (lower.includes('rain')) return '🌧️';
  if (lower.includes('snow')) return '❄️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('wind')) return '💨';
  if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
  return '🌤️'; // default
};

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit,
    forecast = []
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card padding="24" shadow="md">
      <Stack direction="vertical" gap={20}>
        {/* Header - City Name */}
        <div>
          <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)">
            {city}
          </Text>
        </div>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16} align="center">
          {/* Temperature with Emoji */}
          <div style={{
            textAlign: 'center',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: 'var(--ggui-spacing-4, 16px)'
          }}>
            <div style={{
              fontSize: '64px',
              lineHeight: '1',
              marginBottom: 'var(--ggui-spacing-2, 8px)'
            }}>
              {weatherEmoji}
            </div>
            <Text
              variant="h1"
              color="var(--ggui-color-primary-600, #0284c7)"
              align="center"
            >
              {temperature}°{unit}
            </Text>
          </div>

          {/* Weather Condition */}
          <Text
            variant="body"
            color="var(--ggui-color-neutral-600, #4b5563)"
            align="center"
          >
            {condition}
          </Text>
        </Stack>

        {/* Horizontal Divider */}
        <div style={{
          height: '1px',
          backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
          width: '100%'
        }} />

        {/* Humidity and Wind Speed - Side by Side */}
        <Row gap={16} justify="around" align="center">
          <Stack direction="vertical" gap={8} align="center">
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="medium"
            >
              Humidity
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-neutral-900, #111827)"
              align="center"
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap={8} align="center">
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="medium"
            >
              Wind Speed
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-neutral-900, #111827)"
              align="center"
            >
              {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
            </Text>
          </Stack>
        </Row>

        {/* 5-Day Forecast */}
        {forecast.length > 0 && (
          <>
            <div style={{
              height: '1px',
              backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
              width: '100%'
            }} />

            <div>
              <Text
                variant="label"
                color="var(--ggui-color-neutral-700, #374151)"
                weight="semibold"
              >
                5-Day Forecast
              </Text>
            </div>

            <Row gap={8} justify="between" wrap={true}>
              {forecast.slice(0, 5).map((day, index) => {
                const dayEmoji = getWeatherEmoji(day.condition);
                return (
                  <Box
                    key={index}
                    padding="12"
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    style={{
                      flex: '1 1 auto',
                      minWidth: '80px',
                      textAlign: 'center',
                      border: '1px solid var(--ggui-color-primary-200, #bae6fd)'
                    }}
                  >
                    <Stack direction="vertical" gap={8} align="center">
                      <Text
                        variant="label"
                        color="var(--ggui-color-primary-900, #0c4a6e)"
                        weight="semibold"
                      >
                        {day.day}
                      </Text>
                      <div style={{
                        fontSize: '28px',
                        lineHeight: '1'
                      }}>
                        {dayEmoji}
                      </div>
                      <Stack direction="vertical" gap={2} align="center">
                        <Text
                          variant="caption"
                          color="var(--ggui-color-primary-700, #0369a1)"
                          weight="semibold"
                        >
                          {day.high}°
                        </Text>
                        <Text
                          variant="caption"
                          color="var(--ggui-color-neutral-500, #6b7280)"
                        >
                          {day.low}°
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                );
              })}
            </Row>
          </>
        )}
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

function getWeatherEmoji(condition: string): string {
  const normalizedCondition = condition.toLowerCase();

  if (normalizedCondition.includes('sunny') || normalizedCondition.includes('clear')) {
    return '☀️';
  } else if (normalizedCondition.includes('cloud')) {
    return '☁️';
  } else if (normalizedCondition.includes('rain')) {
    return '🌧️';
  } else if (normalizedCondition.includes('snow')) {
    return '❄️';
  } else if (normalizedCondition.includes('wind')) {
    return '💨';
  } else if (normalizedCondition.includes('thunder') || normalizedCondition.includes('storm')) {
    return '⛈️';
  } else if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist')) {
    return '🌫️';
  }
  return '🌤️';
}

export default function WeatherCard(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit,
    forecast = []
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      variant="outlined"
      style={{
        padding: 'var(--ggui-spacing-lg, 24px)',
        backgroundColor: 'var(--ggui-color-background-secondary, #f5f5f5)',
        borderColor: 'var(--ggui-color-border, #e0e0e0)',
      }}
    >
      <Stack direction="vertical" gap="var(--ggui-spacing-md, 16px)">

        {/* Header with city name */}
        <Text
          variant="heading"
          size="lg"
          style={{
            color: 'var(--ggui-color-text-primary, #333)',
          }}
        >
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap="var(--ggui-spacing-sm, 12px)">
          <Stack direction="horizontal" gap="var(--ggui-spacing-md, 16px)" alignment="center">
            <Text
              style={{
                fontSize: '64px',
                lineHeight: '1',
              }}
            >
              {weatherEmoji}
            </Text>

            <Stack direction="vertical" gap="var(--ggui-spacing-xs, 8px)">
              <Text
                style={{
                  fontSize: '48px',
                  fontWeight: '700',
                  lineHeight: '1',
                  color: 'var(--ggui-color-text-primary, #333)',
                }}
              >
                {temperature}°{unit}
              </Text>
              <Text
                style={{
                  fontSize: '16px',
                  color: 'var(--ggui-color-text-secondary, #666)',
                }}
              >
                {condition}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* Current Conditions - Humidity and Wind */}
        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-md, 16px)"
          style={{
            padding: 'var(--ggui-spacing-md, 16px)',
            backgroundColor: 'var(--ggui-color-background-tertiary, #fff)',
            borderRadius: 'var(--ggui-border-radius-md, 8px)',
            borderColor: 'var(--ggui-color-border, #e0e0e0)',
            borderStyle: 'solid',
            borderWidth: '1px',
          }}
        >
          <Stack direction="vertical" gap="var(--ggui-spacing-xs, 8px)" alignment="center">
            <Text
              style={{
                fontSize: '12px',
                color: 'var(--ggui-color-text-secondary, #666)',
              }}
            >
              Humidity
            </Text>
            <Text
              style={{
                fontSize: '18px',
                fontWeight: '600',
                color: 'var(--ggui-color-text-primary, #333)',
              }}
            >
              {humidity}%
            </Text>
          </Stack>

          <div
            style={{
              width: '1px',
              backgroundColor: 'var(--ggui-color-border, #e0e0e0)',
              height: '100%',
            }}
          />

          <Stack direction="vertical" gap="var(--ggui-spacing-xs, 8px)" alignment="center">
            <Text
              style={{
                fontSize: '12px',
                color: 'var(--ggui-color-text-secondary, #666)',
              }}
            >
              Wind Speed
            </Text>
            <Text
              style={{
                fontSize: '18px',
                fontWeight: '600',
                color: 'var(--ggui-color-text-primary, #333)',
              }}
            >
              {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
            </Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast */}
        {forecast && forecast.length > 0 && (
          <Stack direction="vertical" gap="var(--ggui-spacing-sm, 12px)">
            <Text
              style={{
                fontSize: '14px',
                fontWeight: '600',
                color: 'var(--ggui-color-text-secondary, #666)',
              }}
            >
              5-Day Forecast
            </Text>

            <Stack
              direction="horizontal"
              gap="var(--ggui-spacing-sm, 12px)"
              style={{
                overflow: 'auto',
                paddingBottom: 'var(--ggui-spacing-xs, 8px)',
              }}
            >
              {forecast.map((day, index) => (
                <div
                  key={index}
                  style={{
                    minWidth: '90px',
                    padding: 'var(--ggui-spacing-sm, 12px)',
                    backgroundColor: 'var(--ggui-color-background-tertiary, #fff)',
                    borderRadius: 'var(--ggui-border-radius-md, 8px)',
                    borderColor: 'var(--ggui-color-border, #e0e0e0)',
                    borderStyle: 'solid',
                    borderWidth: '1px',
                    textAlign: 'center',
                    transition: 'all 0.2s ease-in-out',
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = 'var(--ggui-color-background-hover, #f9f9f9)';
                    e.currentTarget.style.borderColor = 'var(--ggui-color-primary, #0066cc)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = 'var(--ggui-color-background-tertiary, #fff)';
                    e.currentTarget.style.borderColor = 'var(--ggui-color-border, #e0e0e0)';
                  }}
                >
                  <Text
                    style={{
                      fontSize: '12px',
                      fontWeight: '600',
                      color: 'var(--ggui-color-text-primary, #333)',
                      marginBottom: 'var(--ggui-spacing-xs, 8px)',
                      display: 'block',
                    }}
                  >
                    {day.day}
                  </Text>

                  <Text
                    style={{
                      fontSize: '24px',
                      lineHeight: '1',
                      marginBottom: 'var(--ggui-spacing-xs, 8px)',
                      display: 'block',
                    }}
                  >
                    {day.icon}
                  </Text>

                  <div
                    style={{
                      display: 'flex',
                      justifyContent: 'center',
                      gap: 'var(--ggui-spacing-xs, 8px)',
                      fontSize: '12px',
                    }}
                  >
                    <Text
                      style={{
                        fontWeight: '600',
                        color: 'var(--ggui-color-text-primary, #333)',
                      }}
                    >
                      {day.high}°
                    </Text>
                    <Text
                      style={{
                        color: 'var(--ggui-color-text-secondary, #666)',
                      }}
                    >
                      {day.low}°
                    </Text>
                  </div>
                </div>
              ))}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Stack, Row, Text, Card } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: string;
  forecast?: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloud')) return '☁️';
  if (lowerCondition.includes('rain') || lowerCondition.includes('drizzle')) return '🌧️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('thunder') || lowerCondition.includes('storm')) return '⛈️';
  if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
  if (lowerCondition.includes('wind')) return '💨';
  return '🌤️';
};

export default function GeneratedComponent(props: Props) {
  const {
    city = 'San Francisco',
    temperature = 72,
    condition = 'Sunny',
    humidity = 60,
    windSpeed = 12,
    unit = '°F',
    forecast = [
      { day: 'Mon', icon: '☀️', high: 75, low: 62 },
      { day: 'Tue', icon: '☁️', high: 72, low: 61 },
      { day: 'Wed', icon: '🌧️', high: 68, low: 59 },
      { day: 'Thu', icon: '☀️', high: 73, low: 60 },
      { day: 'Fri', icon: '☁️', high: 71, low: 62 },
    ],
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Stack direction="vertical" gap={0}>
      {/* Header with city name */}
      <Stack
        direction="vertical"
        gap={4}
        align="stretch"
        style={{
          padding: 'var(--ggui-spacing-4)',
          paddingBottom: 'var(--ggui-spacing-2)',
        }}
      >
        <Text
          variant="body"
          weight="semibold"
          color="var(--ggui-color-neutral-700)"
        >
          {city}
        </Text>
      </Stack>

      {/* Current weather section */}
      <Stack
        direction="vertical"
        gap={6}
        align="center"
        style={{
          padding: 'var(--ggui-spacing-4)',
          borderBottom: '1px solid var(--ggui-color-neutral-200)',
        }}
      >
        {/* Temperature and condition */}
        <Stack direction="vertical" gap={4} align="center">
          <div
            style={{
              fontSize: 'var(--ggui-font-size-4xl)',
              lineHeight: 1,
              fontWeight: 'var(--ggui-font-weight-bold)',
