            }}
          >
            {temperature}{unit}
          </div>

          {/* Condition with emoji */}
          <Stack direction="horizontal" gap={6} align="center">
            <div style={{ fontSize: '2rem' }}>{weatherEmoji}</div>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-700)"
              weight="medium"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Humidity and Wind */}
        <Row
          gap={12}
          justify="center"
          align="center"
          style={{
            width: '100%',
          }}
        >
          <Stack direction="vertical" gap={2} align="center">
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500)"
              weight="medium"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="semibold"
              color="var(--ggui-color-neutral-900)"
            >
              {humidity}%
            </Text>
          </Stack>

          <div
            style={{
              width: '1px',
              height: '2rem',
              backgroundColor: 'var(--ggui-color-neutral-200)',
