                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-500)"
                >
                  {day.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Stack>
  );
}

import React from 'react';
import { Container, Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: string;
  forecast?: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition?.toLowerCase() || '';

  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('storm')) return '⛈️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('fog')) return '🌫️';
  if (conditionLower.includes('thunder')) return '⚡';
  return '🌤️'; // Default
};

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', condition: 'sunny', high: 75, low: 62 },
    { day: 'Tue', condition: 'cloudy', high: 73, low: 61 },
    { day: 'Wed', condition: 'rainy', high: 68, low: 58 },
    { day: 'Thu', condition: 'sunny', high: 76, low: 63 },
    { day: 'Fri', condition: 'sunny', high: 78, low: 64 },
  ],
}: Props) {
  return (
    <Box
      style={{
        width: '100vw',
        height: '100dvh',
        backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
        display: 'flex',
        flexDirection: 'column',
        padding: 'var(--ggui-spacing-6, 24px)',
        overflowY: 'auto',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header */}
        <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)">
          {city}
        </Text>

        {/* Main Weather Card */}
        <Card
          padding={32}
          shadow="md"
          style={{
            backgroundColor: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
            borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
          }}
        >
          <Stack direction="vertical" gap={24} align="center">
            {/* Large Temperature Display */}
            <div
              style={{
                display: 'flex',
                alignItems: 'flex-start',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              <Text
                variant="h1"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="bold"
                style={{
                  fontSize: '72px',
                  lineHeight: '1',
                }}
              >
                {Math.round(temperature)}
              </Text>
              <Text
                variant="h2"
                color="var(--ggui-color-primary-700, #0369a1)"
                style={{
                  fontSize: '36px',
                  lineHeight: '1',
                  marginTop: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {unit}
              </Text>
            </div>

            {/* Weather Condition with Emoji */}
            <div style={{ textAlign: 'center' }}>
              <div
                style={{
                  fontSize: '64px',
                  marginBottom: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {getWeatherEmoji(condition)}
              </div>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-800, #075985)"
                weight="semibold"
              >
                {condition}
              </Text>
            </div>

            {/* Humidity and Wind Speed */}
            <Row
              gap={24}
              justify="center"
              wrap
              style={{
                width: '100%',
              }}
            >
              <div style={{ textAlign: 'center', minWidth: '120px' }}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-600, #0284c7)"
                  weight="semibold"
                  style={{
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    textTransform: 'uppercase',
                    letterSpacing: '0.05em',
                  }}
                >
                  Humidity
                </Text>
                <Text
                  variant="h3"
                  color="var(--ggui-color-primary-900, #0c4a6e)"
                  weight="bold"
                  style={{
                    fontSize: '28px',
                    marginTop: 'var(--ggui-spacing-1, 4px)',
                  }}
                >
                  {humidity}%
                </Text>
              </div>

              <div
                style={{
                  width: '1px',
                  backgroundColor: 'var(--ggui-color-primary-200, #bae6fd)',
                  minHeight: '60px',
