import React from 'react'
import { Card, Stack, Row, Box, Text, Divider, Badge } from '@ggui-ai/design/primitives'

type ForecastItem = {
  day?: string
  condition?: string
  high?: number
  low?: number
}

type Props = {
  city: string
  temperature: number
  condition: string
  humidity: number
  windSpeed: number
  unit: string
  forecast: object[]
}

const getConditionIcon = (condition: string): string => {
  const normalized = condition.toLowerCase()
  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️'
  if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️'
  if (normalized.includes('rainy') || normalized.includes('drizzle') || normalized.includes('rain')) return '🌧️'
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️'
  if (normalized.includes('snow')) return '❄️'
  return '🌤️'
}

const formatNumber = (value: number): string => (Number.isFinite(value) ? String(value) : '—')

const formatHumidity = (value: number): string => {
  if (!Number.isFinite(value)) return '—'
  const clamped = Math.max(0, Math.min(100, value))
  return String(clamped) + '%'
}

const getUnitReadable = (unit: string): string => {
  const normalized = unit.trim().toLowerCase()
  if (normalized.includes('c')) return 'Celsius'
  if (normalized.includes('f')) return 'Fahrenheit'
  return unit
}

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props

  const conditionIcon = getConditionIcon(condition || '')
  const safeForecast = (Array.isArray(forecast) ? forecast : []).slice(0, 5) as ForecastItem[]
  const tempDisplay = Number.isFinite(temperature) ? String(temperature) + '°' : '—'
