        maxWidth: '450px',
        width: '100%',
        padding: 'var(--ggui-spacing-6, 24px)',
        borderRadius: 'var(--ggui-radius-xl, 24px)',
        background: 'var(--ggui-color-surface, #ffffff)',
        boxShadow: 'var(--ggui-shadow-md, 0 4px 6px -1px rgba(0, 0, 0, 0.1))',
        border: '1px solid var(--ggui-color-outline-variant, #f0f0f0)'
      }}
    >
      <Stack direction="vertical" gap="xlarge">

        {/* Header Section */}
        <Stack direction="vertical" gap="xsmall">
          <Text 
            variant="headline-sm" 
            weight="bold"
            style={{ color: 'var(--ggui-color-on-surface, #1a1a1a)' }}
          >
            {city}
          </Text>
          <Text 
            variant="body-md" 
            style={{ color: 'var(--ggui-color-on-surface-variant, #666)' }}
          >
            {condition}
          </Text>
        </Stack>

        {/* Temperature & Visual Section */}
        <Stack direction="horizontal" align="center" justify="space-between">
          <Box>
             <Text 
              variant="display-lg" 
              weight="bold"
              style={{ 
                fontSize: 'var(--ggui-font-size-display-large, 3.5rem)',
                lineHeight: 1,
                color: 'var(--ggui-color-primary, #0052cc)'
              }}
            >
              {Math.round(temperature)}{unit}
            </Text>
          </Box>
          <Box style={{ fontSize: '4.5rem', lineHeight: 1 }}>
            {getWeatherEmoji(condition)}
          </Box>
        </Stack>

        {/* Metrics Section */}
        <Stack 
          direction="horizontal" 
          gap="large" 
          style={{ 
            paddingTop: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline-variant, #f0f0f0)' 
          }}
        >
          <Stack direction="vertical" gap="none">
            <Text variant="label-sm" style={{ color: 'var(--ggui-color-on-surface-variant, #666)', letterSpacing: '0.05em' }}>HUMIDITY</Text>
            <Text variant="title-md" weight="medium">{humidity}%</Text>
          </Stack>
          <Stack direction="vertical" gap="none">
            <Text variant="label-sm" style={{ color: 'var(--ggui-color-on-surface-variant, #666)', letterSpacing: '0.05em' }}>WIND</Text>
            <Text variant="title-md" weight="medium">{windSpeed} {unit === '°C' ? 'km/h' : 'mph'}</Text>
          </Stack>
        </Stack>

        {/* Forecast Strip Section */}
        <Stack direction="vertical" gap="medium">
          <Text 
            variant="label-md" 
            weight="bold" 
            style={{ color: 'var(--ggui-color-on-surface, #1a1a1a)', textTransform: 'uppercase' }}
          >
            5-Day Forecast
          </Text>

          <Stack direction="horizontal" justify="space-between" align="stretch" gap="small">
            {forecast.length > 0 ? forecast.slice(0, 5).map((item, index) => (
              <Stack 
                key={index} 
                direction="vertical" 
                align="center" 
                gap="small"
                style={{ 
                  flex: 1,
                  padding: 'var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-radius-md, 12px)',
                  background: 'var(--ggui-color-surface-container-low, #fafafa)',
                  minWidth: '60px'
                }}
              >
                <Text variant="label-sm" weight="bold" style={{ color: 'var(--ggui-color-on-surface-variant, #666)' }}>
                  {item.day.substring(0, 3).toUpperCase()}
                </Text>
                <Box style={{ fontSize: '1.5rem' }}>
                  {getWeatherEmoji(item.condition)}
                </Box>
                <Stack direction="vertical" gap="none" align="center">
                  <Text variant="body-sm" weight="bold">{Math.round(item.high)}°</Text>
                  <Text variant="body-xs" style={{ color: 'var(--ggui-color-on-surface-variant, #888)' }}>{Math.round(item.low)}°</Text>
                </Stack>
              </Stack>
            )) : (
              <Text variant="body-sm" color="subtle">No forecast data available</Text>
            )}
          </Stack>
        </Stack>

      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = '°C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 16 },
    { day: 'Tue', icon: '⛅', high: 22, low: 15 },
    { day: 'Wed', icon: '☁️', high: 20, low: 14 },
    { day: 'Thu', icon: '🌧️', high: 18, low: 13 },
    { day: 'Fri', icon: '⛈️', high: 19, low: 14 },
  ],
}: Props) {
  return (
    <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" border>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack gap={4}>
          <Text variant="h2" weight="bold" color="var(--ggui-color-neutral-900, #111827)">
            {city}
          </Text>
          <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
            Current Weather
          </Text>
        </Stack>

        {/* Main Temperature Section */}
        <Row align="center" justify="between">
          <Stack gap={0}>
            <Text 
              style={{ 
                fontSize: '4rem', 
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                lineHeight: 1,
                color: 'var(--ggui-color-primary-600, #0284c7)'
              }}
            >
              {temperature}{unit}
            </Text>
            <Text variant="h3" weight="semibold" color="var(--ggui-color-neutral-700, #374151)">
              {condition}
            </Text>
          </Stack>

          <Box 
            padding={16} 
            background="var(--ggui-color-primary-50, #f0f9ff)" 
            borderRadius="var(--ggui-shape-radius-full, 9999px)"
            style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <span style={{ fontSize: '3rem' }}>
              {condition.toLowerCase().includes('sunny') ? '☀️' : 
               condition.toLowerCase().includes('cloud') ? '☁️' : 
               condition.toLowerCase().includes('rain') ? '🌧️' : 
               condition.toLowerCase().includes('storm') ? '⛈️' : '⛅'}
            </span>
          </Box>
        </Row>

        {/* Secondary Details */}
        <Row gap={32}>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
              HUMIDITY
            </Text>
            <Text weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
              {humidity}%
            </Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
              WIND
            </Text>
            <Text weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
              {windSpeed} km/h
            </Text>
          </Stack>
        </Row>

        <Divider margin={16} />

        {/* Forecast Section */}
        <Stack gap={16}>
          <Text variant="label" weight="bold" color="var(--ggui-color-neutral-700, #374151)">
            5-DAY FORECAST
          </Text>
          <Row justify="between" wrap>
            {forecast.slice(0, 5).map((day, index) => (
              <Box 
                key={index}
                padding="var(--ggui-spacing-2, 8px)"
                style={{ 
                  textAlign: 'center',
                  minWidth: '60px',
                  flex: 1
                }}
              >
                <Stack align="center" gap={8}>
                  <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500, #6b7280)">
                    {day.day}
                  </Text>
                  <span style={{ fontSize: '1.5rem' }}>{day.icon}</span>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-neutral-900, #111827)">
                      {day.high}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
